import Observable from '../framework/observable.js';
import { FilterType, UpdateType } from '../const.js';
import { adaptPointToClient, adaptPointToServer } from '../adapter/point.js';

function filterPointsByType(points, filterType) {
  const now = new Date();

  switch (filterType) {
    case FilterType.FUTURE:
      return points.filter((point) => point.dateFrom > now);
    case FilterType.PRESENT:
      return points.filter((point) => point.dateFrom <= now && point.dateTo >= now);
    case FilterType.PAST:
      return points.filter((point) => point.dateTo < now);
    case FilterType.EVERYTHING:
    default:
      return [...points];
  }
}

export default class PointsModel extends Observable {
  #apiService;
  #points = [];

  constructor(apiService) {
    super();
    this.#apiService = apiService;
  }

  getPoints(filterType = FilterType.EVERYTHING) {
    return filterPointsByType(this.#points, filterType);
  }

  setPoints(points) {
    this.#points = structuredClone(points.map(adaptPointToClient));
    this._notify(UpdateType.MAJOR);
  }

  addPoint(point) {
    this.#points = [structuredClone(point), ...this.#points];
    this._notify(UpdateType.MAJOR);
  }

  async updatePoint(updatedPoint) {
    const response = await this.#apiService.updatePoint(adaptPointToServer(updatedPoint));
    const adaptedPoint = adaptPointToClient(response);
    const pointIndex = this.#points.findIndex((point) => point.id === updatedPoint.id);

    if (pointIndex === -1) {
      return;
    }

    this.#points = [
      ...this.#points.slice(0, pointIndex),
      structuredClone(adaptedPoint),
      ...this.#points.slice(pointIndex + 1),
    ];

    this._notify(UpdateType.PATCH);

    return adaptedPoint;
  }

  async createPoint(newPoint) {
    const response = await this.#apiService.createPoint(adaptPointToServer(newPoint, {includeId: false}));
    const adaptedPoint = adaptPointToClient(response);

    this.#points = [structuredClone(adaptedPoint), ...this.#points];
    this._notify(UpdateType.MAJOR);

    return adaptedPoint;
  }

  async removePoint(pointId) {
    await this.#apiService.deletePoint(pointId);
    this.#points = this.#points.filter((point) => point.id !== pointId);
    this._notify(UpdateType.MAJOR);
  }
}

